//! # Rune CLI
//!
//! Main CLI entry point for the `rune` binary and `cargo rune` subcommand.

use anyhow::Result;
use clap::{Arg, Command, ValueHint};
use std::path::PathBuf;
use rune::driver::{BuildOptions, BuildMode, Command as RuneCommand};
use tracing_subscriber::{layer::SubscriberExt, util::SubscriberInitExt};

/// Detect if running as cargo subcommand.
fn is_cargo_subcommand() -> bool {
    if let Ok(exe) = std::env::current_exe() {
        if let Some(name) = exe.file_name() {
            if let Some(name_str) = name.to_str() {
                return name_str.starts_with("cargo-");
            }
        }
    }
    false
}

fn main() -> Result<()> {
    // Setup logging
    tracing_subscriber::registry()
        .with(tracing_subscriber::fmt::layer())
        .with(tracing_subscriber::EnvFilter::from_default_env())
        .init();

    // Check invocation mode
    let args: Vec<String> = std::env::args().collect();
    let is_cargo = is_cargo_subcommand();

    // Determine the binary name for clap
    let bin_name = if is_cargo { "cargo rune" } else { "rune" };

    // Build command with dynamic bin_name
    let cmd = Command::new("rune")
        .about("TypeScript to Rust compiler driver")
        .bin_name(bin_name)
        .arg(
            Arg::new("verbose")
                .short('v')
                .long("verbose")
                .action(clap::ArgAction::SetTrue)
                .help("Enable verbose output")
        )
        .subcommand(
            Command::new("dev")
                .about("Development mode with hot reload")
                .arg(
                    Arg::new("path")
                        .help("Working directory")
                        .default_value(".")
                        .value_hint(ValueHint::DirPath)
                )
        )
        .subcommand(
            Command::new("build")
                .about("Release build")
                .arg(Arg::new("release").long("release").action(clap::ArgAction::SetTrue).help("Build release mode"))
                .arg(
                    Arg::new("path")
                        .help("Working directory")
                        .default_value(".")
                        .value_hint(ValueHint::DirPath)
                )
        )
        .subcommand(
            Command::new("check")
                .about("Type check only")
                .arg(
                    Arg::new("path")
                        .help("Working directory")
                        .default_value(".")
                        .value_hint(ValueHint::DirPath)
                )
        )
        .subcommand(
            Command::new("transpile")
                .about("Transpile a file to stdout")
                .arg(Arg::new("file").help("File to transpile").required(true))
        )
        .subcommand(
            Command::new("init")
                .about("Initialize a new project")
                .arg(Arg::new("name").help("Project name"))
        );

    let matches = cmd.get_matches_from(&args);

    let verbose = matches.get_flag("verbose");
    let mut options: BuildOptions;

    // Execute command
    let result = if let Some(m) = matches.subcommand_matches("dev") {
        let path = m.get_one::<String>("path").unwrap();
        options = BuildOptions::new(PathBuf::from(path));
        options.mode = BuildMode::Dev;
        options.verbose = verbose;
        rune::driver::run(RuneCommand::Dev, options)
    } else if let Some(m) = matches.subcommand_matches("build") {
        let path = m.get_one::<String>("path").unwrap();
        let release = m.get_flag("release");
        options = BuildOptions::new(PathBuf::from(path));
        options.mode = if release { BuildMode::Release } else { BuildMode::Dev };
        options.verbose = verbose;
        rune::driver::run(RuneCommand::Build, options)
    } else if let Some(m) = matches.subcommand_matches("check") {
        let path = m.get_one::<String>("path").unwrap();
        options = BuildOptions::new(PathBuf::from(path));
        options.verbose = verbose;
        rune::driver::run(RuneCommand::Check, options)
    } else if let Some(m) = matches.subcommand_matches("transpile") {
        let file = m.get_one::<String>("file").unwrap();
        options = BuildOptions::new(PathBuf::from("."));
        options.transpile_file = Some(PathBuf::from(file));
        options.verbose = verbose;
        rune::driver::run(RuneCommand::Transpile, options)
    } else if let Some(m) = matches.subcommand_matches("init") {
        let name = m.get_one::<String>("name").cloned();
        options = BuildOptions::new(PathBuf::from("."));
        if let Some(n) = name {
            println!("Initializing project: {n}");
        }
        rune::driver::run(RuneCommand::Init, options)
    } else {
        // No subcommand, show help
        println!("Usage: rune <COMMAND>");
        return Ok(());
    };

    if let Err(e) = result {
        eprintln!("Error: {e}");
        std::process::exit(1);
    }

    Ok(())
}

