    /// Development mode with hot reload
    Dev {
        /// Working directory
        #[arg(value_hint = ValueHint::DirPath)]
        path: Option<PathBuf>,
    },

    /// Release build
    Build {
        /// Working directory
        #[arg(value_hint = ValueHint::DirPath)]
        path: Option<PathBuf>,

        /// Build release mode
        #[arg(short, long)]
        release: bool,
    },

    /// Type check only
    Check {
        /// Working directory
        #[arg(value_hint = ValueHint::DirPath)]
        path: Option<PathBuf>,
    },

    /// Transpile a file to stdout
    Transpile {
        /// File to transpile
        file: PathBuf,
    },

    /// Initialize a new project
    Init {
        /// Project name
        name: Option<String>,
    },
}

fn main() -> Result<()> {
    // Setup logging
    tracing_subscriber::registry()
        .with(tracing_subscriber::fmt::layer())
        .with(tracing_subscriber::EnvFilter::from_default_env())
        .init();

    // Check if running as cargo subcommand
    let is_cargo = is_cargo_subcommand();

    // Get command line args
    let mut args: Vec<String> = std::env::args().collect();

    // When cargo invokes cargo-rune, it passes ["cargo", "rune", ...]
    // We need to strip the "rune" arg for clap to work
    if is_cargo && args.len() > 1 && args[1] == "rune" {
        args.remove(1);
    }

    // Parse arguments using clap's from_iter which doesn't consume args
    let cli = Cli::parse_from(&args);

    let mut options: BuildOptions;

    // Execute command
    let result = match &cli.command {
        Commands::Dev { path } => {
            options = BuildOptions::new(path.clone().unwrap_or_else(|| PathBuf::from(".")));
